class Solution:
    def largeGroupPositions(self, s):
        from itertools import groupby
        result = []
        idx = 0
        for _, group in groupby(s):
            length = len(list(group))
            if length >= 3:
                result.append([idx, idx + length - 1])
            idx += length
        return result

